import javax.servlet.http.*;

public class SessionTrackingServlet extends HttpServlet {
 public void doGet(HttpServletRequest request, HttpServletResponse response) {
 HttpSession session = request.getSession();

 if (session.isNew()) {
 // Initialize session data
 session.setAttribute("visitCount", 1);
 } else {
 // Update visit count
 Integer visitCount = (Integer) session.getAttribute("visitCount");
 visitCount++;
 session.setAttribute("visitCount", visitCount);
 }

 // Generate response based on session data
 response.getWriter().println("Visit count: " + session.getAttribute("visitCount"));
 }
}

import javax.servlet.http.*;

public class SessionTimeoutServlet extends HttpServlet {
 public void doGet(HttpServletRequest request, HttpServletResponse response) {
 HttpSession session = request.getSession();

 // Set session timeout to 30 minutes
 session.setMaxInactiveInterval(1800);

 // Get session timeout
 int timeout = session.getMaxInactiveInterval();

 // Generate response based on session timeout
 response.getWriter().println("Session timeout: " + timeout);
 }
}
